using Dapper; using MySqlConnector; using Payroll.API.Models;
namespace Payroll.API.Repositories;
public class WorkflowRepository(IConfiguration configuration)
{
    private MySqlConnection Db() => new(configuration.GetConnectionString("Default"));
    public async Task InitializeAsync(){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");await db.ExecuteAsync(@"CREATE TABLE IF NOT EXISTS WorkflowMasters (Id INT PRIMARY KEY AUTO_INCREMENT,ClientId INT NULL,Code VARCHAR(80) NOT NULL,Name VARCHAR(180) NOT NULL,ResourceType VARCHAR(100) NOT NULL,IsActive BOOLEAN NOT NULL DEFAULT TRUE,CreatedAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,UpdatedAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY UX_Workflow_Client_Code (ClientId,Code));CREATE TABLE IF NOT EXISTS WorkflowStages (Id INT PRIMARY KEY AUTO_INCREMENT,WorkflowId INT NOT NULL,StageOrder INT NOT NULL,Name VARCHAR(180) NOT NULL,ApproverType VARCHAR(40) NOT NULL,ApproverUserId INT NULL,UNIQUE KEY UX_WorkflowStage_Order (WorkflowId,StageOrder));CREATE TABLE IF NOT EXISTS DepartmentHeadAssignments (Id INT PRIMARY KEY AUTO_INCREMENT,ClientId INT NOT NULL,Department VARCHAR(100) NOT NULL,UserId INT NOT NULL,UNIQUE KEY UX_DepartmentHeadAssignment (ClientId,Department));CREATE TABLE IF NOT EXISTS WorkflowInstances (Id BIGINT PRIMARY KEY AUTO_INCREMENT,WorkflowId INT NOT NULL,ResourceType VARCHAR(100) NOT NULL,ResourceId VARCHAR(120) NOT NULL,RequestorUserId INT NOT NULL,PayloadJson JSON NOT NULL,Status VARCHAR(30) NOT NULL DEFAULT 'Pending',CreatedAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,CompletedAt DATETIME NULL,INDEX IX_WorkflowInstances_Resource (ResourceType,ResourceId));CREATE TABLE IF NOT EXISTS WorkflowTasks (Id BIGINT PRIMARY KEY AUTO_INCREMENT,InstanceId BIGINT NOT NULL,StageId INT NOT NULL,ApproverUserId INT NOT NULL,Status VARCHAR(30) NOT NULL DEFAULT 'Pending',CreatedAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,ActionedAt DATETIME NULL,Comment VARCHAR(1000),INDEX IX_WorkflowTasks_Approver_Status (ApproverUserId,Status));CREATE TABLE IF NOT EXISTS WorkflowHistory (Id BIGINT PRIMARY KEY AUTO_INCREMENT,InstanceId BIGINT NOT NULL,TaskId BIGINT NULL,Action VARCHAR(30) NOT NULL,ActorUserId INT NOT NULL,Comment VARCHAR(1000),CreatedAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,INDEX IX_WorkflowHistory_Instance (InstanceId,CreatedAt));");await EnsureForeignKeyAsync(db,"WorkflowStages","FK_WorkflowStages_Master","FOREIGN KEY (WorkflowId) REFERENCES WorkflowMasters(Id) ON DELETE CASCADE");}
    public async Task<IEnumerable<WorkflowMaster>> GetAsync(){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");var rows=(await db.QueryAsync<WorkflowMaster>("SELECT * FROM WorkflowMasters ORDER BY Name")).ToList();var stages=await db.QueryAsync<WorkflowStage>("SELECT * FROM WorkflowStages ORDER BY StageOrder");foreach(var row in rows)row.Stages=stages.Where(x=>x.WorkflowId==row.Id).ToList();return rows;}
    public async Task<IEnumerable<WorkflowApprover>> GetApproversAsync(){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");return await db.QueryAsync<WorkflowApprover>("SELECT u.Id,u.DisplayName,u.Email,u.ClientId,COALESCE(c.Name,'All clients') ClientName FROM AuthUsers u LEFT JOIN Clients c ON c.Id=u.ClientId WHERE u.IsActive=TRUE ORDER BY u.DisplayName");}
    public async Task<IEnumerable<string>> GetDepartmentsAsync(int clientId){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");return await db.QueryAsync<string>("SELECT DISTINCT Department FROM Employees WHERE ClientId=@ClientId AND IsActive=TRUE AND Department<>'' ORDER BY Department",new{ClientId=clientId});}
    public async Task<IEnumerable<DepartmentHeadAssignment>> GetDepartmentHeadsAsync(int clientId){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");return await db.QueryAsync<DepartmentHeadAssignment>("SELECT a.Id,a.ClientId,a.Department,a.UserId,u.DisplayName UserName FROM DepartmentHeadAssignments a JOIN AuthUsers u ON u.Id=a.UserId WHERE a.ClientId=@ClientId ORDER BY a.Department",new{ClientId=clientId});}
    public async Task<DepartmentHeadAssignment> SaveDepartmentHeadAsync(SaveDepartmentHeadAssignmentRequest request){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");await db.ExecuteAsync("INSERT INTO DepartmentHeadAssignments (ClientId,Department,UserId) VALUES (@ClientId,@Department,@UserId) ON DUPLICATE KEY UPDATE UserId=VALUES(UserId)",request);return await db.QuerySingleAsync<DepartmentHeadAssignment>("SELECT a.Id,a.ClientId,a.Department,a.UserId,u.DisplayName UserName FROM DepartmentHeadAssignments a JOIN AuthUsers u ON u.Id=a.UserId WHERE a.ClientId=@ClientId AND a.Department=@Department",request);}
    public async Task<int?> GetDefaultIdAsync(string resourceType,int? clientId){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");return await db.ExecuteScalarAsync<int?>("SELECT Id FROM WorkflowMasters WHERE ResourceType=@ResourceType AND IsActive=TRUE AND (ClientId=@ClientId OR ClientId IS NULL) ORDER BY ClientId IS NULL, Id LIMIT 1",new{ResourceType=resourceType,ClientId=clientId});}
    public async Task<WorkflowMaster> SaveAsync(SaveWorkflowRequest r){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");await using var tx=await db.BeginTransactionAsync();var id=r.Id;if(id==0)id=(int)await db.ExecuteScalarAsync<long>("INSERT INTO WorkflowMasters (ClientId,Code,Name,ResourceType,IsActive) VALUES (@ClientId,@Code,@Name,@ResourceType,@IsActive);SELECT LAST_INSERT_ID();",r,tx);else await db.ExecuteAsync("UPDATE WorkflowMasters SET ClientId=@ClientId,Code=@Code,Name=@Name,ResourceType=@ResourceType,IsActive=@IsActive WHERE Id=@Id",r,tx);await db.ExecuteAsync("DELETE FROM WorkflowStages WHERE WorkflowId=@Id",new{Id=id},tx);foreach(var s in r.Stages.OrderBy(x=>x.StageOrder))await db.ExecuteAsync("INSERT INTO WorkflowStages (WorkflowId,StageOrder,Name,ApproverType,ApproverUserId) VALUES (@WorkflowId,@StageOrder,@Name,@ApproverType,@ApproverUserId)",new{WorkflowId=id,s.StageOrder,s.Name,s.ApproverType,s.ApproverUserId},tx);await tx.CommitAsync();return (await GetAsync()).First(x=>x.Id==id);}
    public async Task<WorkflowInstance?> StartAsync(StartWorkflowRequest r,int requestor){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");var master=await db.QueryFirstOrDefaultAsync<WorkflowMaster>("SELECT * FROM WorkflowMasters WHERE Id=@WorkflowId AND IsActive=TRUE",r);if(master is null)return null;var stage=await db.QueryFirstOrDefaultAsync<WorkflowStage>("SELECT * FROM WorkflowStages WHERE WorkflowId=@WorkflowId ORDER BY StageOrder LIMIT 1",r);if(stage is null)return null;var approver=await ResolveAsync(db,stage,requestor);if(approver is null)return null;var id=await db.ExecuteScalarAsync<long>("INSERT INTO WorkflowInstances (WorkflowId,ResourceType,ResourceId,RequestorUserId,PayloadJson) VALUES (@WorkflowId,@ResourceType,@ResourceId,@Requestor,@PayloadJson);SELECT LAST_INSERT_ID();",new{r.WorkflowId,r.ResourceType,r.ResourceId,Requestor=requestor,r.PayloadJson});var task=await db.ExecuteScalarAsync<long>("INSERT INTO WorkflowTasks (InstanceId,StageId,ApproverUserId) VALUES (@Id,@StageId,@Approver);SELECT LAST_INSERT_ID();",new{Id=id,StageId=stage.Id,Approver=approver});await db.ExecuteAsync("INSERT INTO WorkflowHistory (InstanceId,TaskId,Action,ActorUserId,Comment) VALUES (@Id,@Task,'Started',@User,'')",new{Id=id,Task=task,User=requestor});return await db.QueryFirstAsync<WorkflowInstance>("SELECT * FROM WorkflowInstances WHERE Id=@Id",new{Id=id});}
    public async Task<IEnumerable<WorkflowTask>> PendingAsync(int userId){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");return await db.QueryAsync<WorkflowTask>(@"SELECT t.*,s.Name AS StageName,i.ResourceType,i.ResourceId,i.PayloadJson FROM WorkflowTasks t JOIN WorkflowStages s ON s.Id=t.StageId JOIN WorkflowInstances i ON i.Id=t.InstanceId WHERE t.ApproverUserId=@UserId AND t.Status='Pending' ORDER BY t.CreatedAt",new{UserId=userId});}
    public async Task<IEnumerable<WorkflowHistoryItem>> GetInstancesAsync(){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");return await db.QueryAsync<WorkflowHistoryItem>(@"SELECT i.Id,m.Name WorkflowName,i.ResourceType,i.ResourceId,i.PayloadJson,COALESCE(u.DisplayName,'Unknown') RequestorName,i.Status,i.CreatedAt,i.CompletedAt FROM WorkflowInstances i JOIN WorkflowMasters m ON m.Id=i.WorkflowId LEFT JOIN AuthUsers u ON u.Id=i.RequestorUserId ORDER BY i.CreatedAt DESC LIMIT 250");}
    public async Task<IEnumerable<dynamic>> HistoryAsync(long instanceId){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");return await db.QueryAsync(@"SELECT h.Id,h.Action,h.Comment,h.CreatedAt,u.DisplayName AS Actor FROM WorkflowHistory h LEFT JOIN AuthUsers u ON u.Id=h.ActorUserId WHERE h.InstanceId=@InstanceId ORDER BY h.CreatedAt",new{InstanceId=instanceId});}
    public async Task<WorkflowInstance?> GetInstanceAsync(long instanceId){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");return await db.QueryFirstOrDefaultAsync<WorkflowInstance>("SELECT * FROM WorkflowInstances WHERE Id=@Id",new{Id=instanceId});}
    public async Task<WorkflowInstance?> GetInstanceForTaskAsync(long taskId){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");return await db.QueryFirstOrDefaultAsync<WorkflowInstance>("SELECT i.* FROM WorkflowInstances i JOIN WorkflowTasks t ON t.InstanceId=i.Id WHERE t.Id=@TaskId",new{TaskId=taskId});}
    public async Task<bool> ActionAsync(long taskId,int actor,string action,string comment){await using var db=Db();await db.OpenAsync();await db.ExecuteAsync("USE payroll;");var task=await db.QueryFirstOrDefaultAsync<WorkflowTask>("SELECT * FROM WorkflowTasks WHERE Id=@Id AND ApproverUserId=@Actor AND Status='Pending'",new{Id=taskId,Actor=actor});if(task is null)return false;await db.ExecuteAsync("UPDATE WorkflowTasks SET Status=@Action,ActionedAt=UTC_TIMESTAMP(),Comment=@Comment WHERE Id=@Id",new{Action=action,Comment=comment,Id=taskId});await db.ExecuteAsync("INSERT INTO WorkflowHistory (InstanceId,TaskId,Action,ActorUserId,Comment) VALUES (@InstanceId,@TaskId,@Action,@Actor,@Comment)",new{task.InstanceId,TaskId=taskId,Action=action,Actor=actor,Comment=comment});if(action=="Approved")await AdvanceAsync(db,task.InstanceId,task.StageId,actor);else await db.ExecuteAsync("UPDATE WorkflowInstances SET Status=@Status,CompletedAt=UTC_TIMESTAMP() WHERE Id=@Id",new{Status=action,Id=task.InstanceId});return true;}
    private static async Task<int?> ResolveAsync(MySqlConnection db,WorkflowStage s,int requestor){if(s.ApproverType=="Specific User")return await db.ExecuteScalarAsync<int?>("SELECT Id FROM AuthUsers WHERE Id=@Id AND IsActive=TRUE",new{Id=s.ApproverUserId});if(s.ApproverType=="HR Manager")return await db.ExecuteScalarAsync<int?>("SELECT u.Id FROM AuthUsers u JOIN AuthUserRoles ur ON ur.UserId=u.Id JOIN AuthRoles r ON r.Id=ur.RoleId JOIN AuthUsers requester ON requester.Id=@Requestor LEFT JOIN Employees e ON e.Id=requester.EmployeeId WHERE r.Code='hr_manager' AND u.IsActive=TRUE AND (u.ClientId=e.ClientId OR u.ClientId IS NULL) ORDER BY u.ClientId IS NULL LIMIT 1",new{Requestor=requestor});if(s.ApproverType=="Reporting Manager")return await db.ExecuteScalarAsync<int?>("SELECT u.Id FROM AuthUsers u JOIN Employees e ON e.ReportingManagerId=u.EmployeeId JOIN AuthUsers requester ON requester.EmployeeId=e.Id WHERE requester.Id=@Requestor AND u.IsActive=TRUE LIMIT 1",new{Requestor=requestor});if(s.ApproverType=="Department Head")return await db.ExecuteScalarAsync<int?>("SELECT u.Id FROM DepartmentHeadAssignments a JOIN AuthUsers u ON u.Id=a.UserId AND u.IsActive=TRUE JOIN AuthUsers requester ON requester.Id=@Requestor JOIN Employees employee ON employee.Id=requester.EmployeeId WHERE a.ClientId=employee.ClientId AND a.Department=employee.Department",new{Requestor=requestor});return null;}
    private static async Task AdvanceAsync(MySqlConnection db,long instanceId,int stageId,int actor){var next=await db.QueryFirstOrDefaultAsync<WorkflowStage>("SELECT s.* FROM WorkflowStages s JOIN WorkflowTasks t ON t.StageId=s.Id WHERE t.InstanceId=@InstanceId AND s.StageOrder>(SELECT StageOrder FROM WorkflowStages WHERE Id=@StageId) ORDER BY s.StageOrder LIMIT 1",new{InstanceId=instanceId,StageId=stageId});if(next is null){await db.ExecuteAsync("UPDATE WorkflowInstances SET Status='Approved',CompletedAt=UTC_TIMESTAMP() WHERE Id=@Id",new{Id=instanceId});return;}var approver=await ResolveAsync(db,next,actor);if(approver is null){await db.ExecuteAsync("UPDATE WorkflowInstances SET Status='Failed',CompletedAt=UTC_TIMESTAMP() WHERE Id=@Id",new{Id=instanceId});return;}await db.ExecuteAsync("INSERT INTO WorkflowTasks (InstanceId,StageId,ApproverUserId) VALUES (@InstanceId,@StageId,@Approver)",new{InstanceId=instanceId,StageId=next.Id,Approver=approver});}
    private static async Task EnsureForeignKeyAsync(MySqlConnection db,string tableName,string constraintName,string definition){var exists=await db.ExecuteScalarAsync<int>("SELECT COUNT(*) FROM INFORMATION_SCHEMA.REFERENTIAL_CONSTRAINTS WHERE CONSTRAINT_SCHEMA='payroll' AND CONSTRAINT_NAME=@ConstraintName",new{ConstraintName=constraintName});if(exists==0)await db.ExecuteAsync($"ALTER TABLE `{tableName}` ADD CONSTRAINT `{constraintName}` {definition}");}
}
